+using System.Collections.Concurrent;
+
+namespace API.Middleware;
+
+public class RateLimitingMiddleware
+{
+    private readonly RequestDelegate _next;
+    private readonly ILogger<RateLimitingMiddleware> _logger;
+    private readonly ConcurrentDictionary<string, RateLimitInfo> _clients;
+    private readonly int _maxRequests = 100;
+    private readonly TimeSpan _timeWindow = TimeSpan.FromMinutes(1);
+
+    public RateLimitingMiddleware(RequestDelegate next, ILogger<RateLimitingMiddleware> logger)
+    {
+        _next = next;
+        _logger = logger;
+        _clients = new ConcurrentDictionary<string, RateLimitInfo>();
+    }
+
+    public async Task InvokeAsync(HttpContext context)
+    {
+        var clientId = GetClientIdentifier(context);
+        var now = DateTime.UtcNow;
+
+        var rateLimitInfo = _clients.AddOrUpdate(clientId,
+            new RateLimitInfo { Count = 1, WindowStart = now },
+            (key, existing) =>
+            {
+                if (now - existing.WindowStart > _timeWindow)
+                {
+                    existing.Count = 1;
+                    existing.WindowStart = now;
+                }
+                else
+                {
+                    existing.Count++;
+                }
+                return existing;
+            });
+
+        if (rateLimitInfo.Count > _maxRequests)
+        {
+            _logger.LogWarning("Rate limit exceeded for client {ClientId}", clientId);
+            context.Response.StatusCode = 429;
+            await context.Response.WriteAsync("Rate limit exceeded. Try again later.");
+            return;
+        }
+
+        await _next(context);
+    }
+
+    private string GetClientIdentifier(HttpContext context)
+    {
+        // Use IP address or API key as identifier
+        return context.Connection.RemoteIpAddress?.ToString() ?? "unknown";
+    }
+
+    private class RateLimitInfo
+    {
+        public int Count { get; set; }
+        public DateTime WindowStart { get; set; }
+    }
+}

