+using Xunit;
+using Microsoft.AspNetCore.TestHost;
+
+namespace API.Tests;
+
+public class RateLimitingTests
+{
+    [Fact]
+    public async Task RateLimiting_ShouldReturn429_WhenLimitExceeded()
+    {
+        // Arrange
+        var server = new TestServer(new WebHostBuilder().UseStartup<Startup>());
+        var client = server.CreateClient();
+
+        // Act - Send more than 100 requests
+        for (int i = 0; i < 101; i++)
+        {
+            await client.GetAsync("/api/test");
+        }
+
+        var response = await client.GetAsync("/api/test");
+
+        // Assert
+        Assert.Equal(429, (int)response.StatusCode);
+    }
+
+    [Fact]
+    public async Task RateLimiting_ShouldResetAfterTimeWindow()
+    {
+        // Arrange
+        var server = new TestServer(new WebHostBuilder().UseStartup<Startup>());
+        var client = server.CreateClient();
+
+        // Act - Wait for time window to reset
+        await Task.Delay(TimeSpan.FromMinutes(1.1));
+        var response = await client.GetAsync("/api/test");
+
+        // Assert
+        Assert.Equal(200, (int)response.StatusCode);
+    }
+}
